    }
  },
  methods: {
    setTheme(theme) {
      this.currentTheme = `theme-${theme}`
      localStorage.setItem('theme', this.currentTheme)
    }
  },
  created() {
    const savedTheme = localStorage.getItem('theme')
    if (savedTheme) {
      this.currentTheme = savedTheme
    }
  }
}
